// Package federation defines the hub-side federation registry: state types,
// persistence, and reconciliation helpers. No HTTP layer here — that lands in
// later beads. The on-disk format carries a schema_version field for forward
// compatibility (see ADR-007 and FEAT-026).
package federation

import (
	"fmt"
	"time"
)

// CurrentSchemaVersion is the schema_version this build writes. Reading code
// must accept older versions and migrate; writing code always emits this.
const CurrentSchemaVersion = "1"

// SpokeStatus is the lifecycle/health status of a registered spoke.
//
// The states are:
//   - StatusRegistered: spoke has registered but no heartbeat has been observed yet.
//   - StatusActive:     last heartbeat is recent (the live/healthy state).
//   - StatusStale:      no heartbeat for ≥ 2 minutes.
//   - StatusOffline:    fan-out to the spoke failed (connection refused, unreachable).
//   - StatusDegraded:   version handshake accepted with minor/schema drift.
//
// The bead-level enum collapses ADR-007's split between compat_status and
// liveness into a single field for v1 persistence; richer surface fields can
// be added in later schema versions without breaking older readers.
type SpokeStatus string

const (
	StatusRegistered SpokeStatus = "registered"
	StatusActive     SpokeStatus = "active"
	StatusStale      SpokeStatus = "stale"
	StatusOffline    SpokeStatus = "offline"
	StatusDegraded   SpokeStatus = "degraded"
)

// Valid reports whether s is one of the known status values.
func (s SpokeStatus) Valid() bool {
	switch s {
	case StatusRegistered, StatusActive, StatusStale, StatusOffline, StatusDegraded:
		return true
	}
	return false
}

// SpokeRecord is one entry in the federation registry.
type SpokeRecord struct {
	NodeID         string      `json:"node_id"`
	Name           string      `json:"name"`
	URL            string      `json:"url"`
	DDxVersion     string      `json:"ddx_version,omitempty"`
	SchemaVersion  string      `json:"schema_version,omitempty"`
	Capabilities   []string    `json:"capabilities,omitempty"`
	RegisteredAt   time.Time   `json:"registered_at"`
	LastHeartbeat  time.Time   `json:"last_heartbeat"`
	Status         SpokeStatus `json:"status"`
}

// FederationRegistry is the persisted hub state.
type FederationRegistry struct {
	SchemaVersion string        `json:"schema_version"`
	Spokes        []SpokeRecord `json:"spokes"`
}

// NewRegistry returns an empty registry stamped with the current schema version.
func NewRegistry() *FederationRegistry {
	return &FederationRegistry{
		SchemaVersion: CurrentSchemaVersion,
		Spokes:        []SpokeRecord{},
	}
}

// FindSpoke returns the record for nodeID, or nil if absent.
func (r *FederationRegistry) FindSpoke(nodeID string) *SpokeRecord {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			return &r.Spokes[i]
		}
	}
	return nil
}

// UpsertSpoke inserts or replaces a spoke by NodeID. NodeID must be non-empty.
func (r *FederationRegistry) UpsertSpoke(rec SpokeRecord) error {
	if rec.NodeID == "" {
		return fmt.Errorf("federation: spoke node_id is required")
	}
	if rec.Status == "" {
		rec.Status = StatusRegistered
	}
	if !rec.Status.Valid() {
		return fmt.Errorf("federation: invalid spoke status %q", rec.Status)
	}
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == rec.NodeID {
			r.Spokes[i] = rec
			return nil
		}
	}
	r.Spokes = append(r.Spokes, rec)
	return nil
}

// RemoveSpoke removes a spoke by NodeID; reports whether it was present.
func (r *FederationRegistry) RemoveSpoke(nodeID string) bool {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			r.Spokes = append(r.Spokes[:i], r.Spokes[i+1:]...)
			return true
		}
	}
	return false
}

// SetStatus updates the status of a spoke and returns true on success. Refuses
// unknown status values so callers cannot silently corrupt persisted state.
func (r *FederationRegistry) SetStatus(nodeID string, status SpokeStatus) error {
	if !status.Valid() {
		return fmt.Errorf("federation: invalid status %q", status)
	}
	rec := r.FindSpoke(nodeID)
	if rec == nil {
		return fmt.Errorf("federation: spoke %q not found", nodeID)
	}
	rec.Status = status
	return nil
}

// ReconcileLiveness derives status purely from elapsed time since the last
// heartbeat for spokes whose status is currently in {registered, active,
// stale}. Statuses set externally (offline from fan-out failure, degraded from
// version handshake) are left alone — those are not time-driven.
//
//   - now - last_heartbeat <  staleAfter            → active
//   - now - last_heartbeat >= staleAfter            → stale
//
// A zero LastHeartbeat keeps a freshly-registered spoke in StatusRegistered
// until the first heartbeat is observed.
func (r *FederationRegistry) ReconcileLiveness(now time.Time, staleAfter time.Duration) {
	for i := range r.Spokes {
		s := &r.Spokes[i]
		switch s.Status {
		case StatusOffline, StatusDegraded:
			continue
		}
		if s.LastHeartbeat.IsZero() {
			s.Status = StatusRegistered
			continue
		}
		if now.Sub(s.LastHeartbeat) >= staleAfter {
			s.Status = StatusStale
		} else {
			s.Status = StatusActive
		}
	}
}

package federation

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"sync"
)

// stateFileName is the on-disk filename, under XDG_DATA_HOME / ~/.local/share.
const stateFileName = "federation-state.json"

// fileMode is mode 0600: registry may carry spoke URLs and identity, so it is
// owner-readable only (FEAT-026 NFR).
const fileMode os.FileMode = 0o600

// dirMode for the parent directory.
const dirMode os.FileMode = 0o700

// writeMu serializes concurrent SaveStateTo calls within one process so
// tmpfile+rename does not race against itself. (Cross-process safety relies
// on rename atomicity.)
var writeMu sync.Mutex

// DefaultStatePath returns ~/.local/share/ddx/federation-state.json.
// Honors XDG_DATA_HOME when set, otherwise falls back to ~/.local/share.
func DefaultStatePath() (string, error) {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx", stateFileName), nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
	}
	return filepath.Join(home, ".local", "share", "ddx", stateFileName), nil
}

// LoadState reads the registry from the default path.
func LoadState() (*FederationRegistry, error) {
	path, err := DefaultStatePath()
	if err != nil {
		return nil, err
	}
	return LoadStateFrom(path)
}

// SaveState writes the registry to the default path.
func SaveState(r *FederationRegistry) error {
	path, err := DefaultStatePath()
	if err != nil {
		return err
	}
	return SaveStateTo(path, r)
}

// LoadStateFrom reads the registry from path. Behavior:
//
//   - Missing file       → fresh empty registry stamped with CurrentSchemaVersion.
//   - Malformed JSON     → fresh empty registry; the corrupt file is renamed
//     to "<path>.corrupt-<ts>" so an operator can recover it.
//   - Unknown future     → loaded as-is; caller can inspect SchemaVersion and
//     schema_version       decide whether to refuse to write.
func LoadStateFrom(path string) (*FederationRegistry, error) {
	data, err := os.ReadFile(path)
	if errors.Is(err, os.ErrNotExist) {
		return NewRegistry(), nil
	}
	if err != nil {
		return nil, fmt.Errorf("federation: read state: %w", err)
	}

	var reg FederationRegistry
	if err := json.Unmarshal(data, &reg); err != nil {
		// Quarantine the corrupt file so it's not silently overwritten on the
		// next save, then return a fresh registry. This is the recovery path
		// the bead's "malformed-file recovery" AC asks for.
		_ = quarantineCorrupt(path)
		return NewRegistry(), nil
	}

	if reg.SchemaVersion == "" {
		// Pre-versioned files are treated as v1; future migrations would key
		// off the read SchemaVersion before this defaulting.
		reg.SchemaVersion = CurrentSchemaVersion
	}
	if reg.Spokes == nil {
		reg.Spokes = []SpokeRecord{}
	}
	return &reg, nil
}

// SaveStateTo writes the registry to path atomically: marshal → write tmpfile
// in the same directory → fsync → rename onto the target. The rename is
// atomic on POSIX filesystems, so a partially-written file is never visible.
func SaveStateTo(path string, r *FederationRegistry) error {
	if r == nil {
		return fmt.Errorf("federation: nil registry")
	}
	if r.SchemaVersion == "" {
		r.SchemaVersion = CurrentSchemaVersion
	}
	if r.Spokes == nil {
		r.Spokes = []SpokeRecord{}
	}

	writeMu.Lock()
	defer writeMu.Unlock()

	if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
		return fmt.Errorf("federation: mkdir: %w", err)
	}

	data, err := json.MarshalIndent(r, "", "  ")
	if err != nil {
		return fmt.Errorf("federation: marshal: %w", err)
	}

	tmp, err := os.CreateTemp(filepath.Dir(path), ".federation-state-*.json.tmp")
	if err != nil {
		return fmt.Errorf("federation: create tmpfile: %w", err)
	}
	tmpPath := tmp.Name()
	cleanup := func() { _ = os.Remove(tmpPath) }

	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		cleanup()
		return fmt.Errorf("federation: write tmpfile: %w", err)
	}
	if err := tmp.Sync(); err != nil {
		_ = tmp.Close()
		cleanup()
		return fmt.Errorf("federation: fsync tmpfile: %w", err)
	}
	if err := tmp.Close(); err != nil {
		cleanup()
		return fmt.Errorf("federation: close tmpfile: %w", err)
	}
	if err := os.Chmod(tmpPath, fileMode); err != nil {
		cleanup()
		return fmt.Errorf("federation: chmod tmpfile: %w", err)
	}
	if err := os.Rename(tmpPath, path); err != nil {
		cleanup()
		return fmt.Errorf("federation: rename: %w", err)
	}
	return nil
}

func quarantineCorrupt(path string) error {
	info, err := os.Stat(path)
	if err != nil || info.IsDir() {
		return err
	}
	bak := fmt.Sprintf("%s.corrupt-%d", path, info.ModTime().UnixNano())
	return os.Rename(path, bak)
}

package federation

import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"testing"
	"time"
)

func sampleSpoke(id, name string, hb time.Time) SpokeRecord {
	return SpokeRecord{
		NodeID:        id,
		Name:          name,
		URL:           "https://" + name + ":7743",
		DDxVersion:    "0.42.0",
		SchemaVersion: "1",
		Capabilities:  []string{"beads", "runs"},
		RegisteredAt:  time.Date(2026, 5, 2, 19, 58, 33, 0, time.UTC),
		LastHeartbeat: hb,
		Status:        StatusActive,
	}
}

func TestRoundTrip(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "federation-state.json")

	in := NewRegistry()
	hb := time.Date(2026, 5, 2, 20, 0, 1, 0, time.UTC)
	if err := in.UpsertSpoke(sampleSpoke("node-1", "bragi", hb)); err != nil {
		t.Fatalf("upsert: %v", err)
	}
	if err := in.UpsertSpoke(sampleSpoke("node-2", "eitri", hb)); err != nil {
		t.Fatalf("upsert: %v", err)
	}
	if err := SaveStateTo(path, in); err != nil {
		t.Fatalf("save: %v", err)
	}

	// File contents must be valid JSON and carry schema_version.
	raw, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("read: %v", err)
	}
	var generic map[string]any
	if err := json.Unmarshal(raw, &generic); err != nil {
		t.Fatalf("file is not valid json: %v", err)
	}
	if generic["schema_version"] != CurrentSchemaVersion {
		t.Fatalf("missing/wrong schema_version field in file: %v", generic["schema_version"])
	}

	// File mode must be 0600 per FEAT-026 NFR.
	info, err := os.Stat(path)
	if err != nil {
		t.Fatalf("stat: %v", err)
	}
	if info.Mode().Perm() != 0o600 {
		t.Fatalf("file mode = %v, want 0600", info.Mode().Perm())
	}

	out, err := LoadStateFrom(path)
	if err != nil {
		t.Fatalf("load: %v", err)
	}
	if out.SchemaVersion != CurrentSchemaVersion {
		t.Fatalf("schema version round-trip: got %q", out.SchemaVersion)
	}
	if len(out.Spokes) != 2 {
		t.Fatalf("spoke count: got %d", len(out.Spokes))
	}
	if got := out.FindSpoke("node-2"); got == nil || got.Name != "eitri" {
		t.Fatalf("spoke lookup failed: %+v", got)
	}
}

func TestLoadMissingFileReturnsFreshRegistry(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "missing.json")

	r, err := LoadStateFrom(path)
	if err != nil {
		t.Fatalf("load missing: %v", err)
	}
	if r.SchemaVersion != CurrentSchemaVersion {
		t.Fatalf("fresh registry schema_version: got %q", r.SchemaVersion)
	}
	if len(r.Spokes) != 0 {
		t.Fatalf("fresh registry should be empty, got %d", len(r.Spokes))
	}
}

func TestLoadMalformedFileRecovers(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "federation-state.json")
	if err := os.WriteFile(path, []byte("not json {{{"), 0o600); err != nil {
		t.Fatalf("write: %v", err)
	}

	r, err := LoadStateFrom(path)
	if err != nil {
		t.Fatalf("load malformed: %v", err)
	}
	if len(r.Spokes) != 0 || r.SchemaVersion != CurrentSchemaVersion {
		t.Fatalf("expected fresh registry, got %+v", r)
	}

	// Corrupt file should have been quarantined, not the live path.
	entries, err := os.ReadDir(dir)
	if err != nil {
		t.Fatalf("readdir: %v", err)
	}
	var foundQuarantine bool
	for _, e := range entries {
		if strings.Contains(e.Name(), ".corrupt-") {
			foundQuarantine = true
		}
	}
	if !foundQuarantine {
		t.Fatalf("expected quarantined .corrupt-* file, got %v", entries)
	}

	// And a subsequent save+load works cleanly.
	r2 := NewRegistry()
	_ = r2.UpsertSpoke(sampleSpoke("node-x", "x", time.Now().UTC()))
	if err := SaveStateTo(path, r2); err != nil {
		t.Fatalf("save after recovery: %v", err)
	}
	r3, err := LoadStateFrom(path)
	if err != nil || len(r3.Spokes) != 1 {
		t.Fatalf("post-recovery load: %v %+v", err, r3)
	}
}

func TestStatusTransitions(t *testing.T) {
	r := NewRegistry()
	now := time.Date(2026, 5, 2, 20, 0, 0, 0, time.UTC)

	// Fresh register, no heartbeat yet.
	rec := sampleSpoke("node-1", "bragi", time.Time{})
	rec.Status = StatusRegistered
	if err := r.UpsertSpoke(rec); err != nil {
		t.Fatalf("upsert: %v", err)
	}

	r.ReconcileLiveness(now, 2*time.Minute)
	if got := r.FindSpoke("node-1").Status; got != StatusRegistered {
		t.Fatalf("zero heartbeat → registered, got %q", got)
	}

	// Recent heartbeat → active.
	r.FindSpoke("node-1").LastHeartbeat = now.Add(-30 * time.Second)
	r.ReconcileLiveness(now, 2*time.Minute)
	if got := r.FindSpoke("node-1").Status; got != StatusActive {
		t.Fatalf("recent hb → active, got %q", got)
	}

	// Heartbeat older than staleAfter → stale.
	r.FindSpoke("node-1").LastHeartbeat = now.Add(-3 * time.Minute)
	r.ReconcileLiveness(now, 2*time.Minute)
	if got := r.FindSpoke("node-1").Status; got != StatusStale {
		t.Fatalf("old hb → stale, got %q", got)
	}

	// Offline status is sticky against time-based reconciliation.
	if err := r.SetStatus("node-1", StatusOffline); err != nil {
		t.Fatalf("set offline: %v", err)
	}
	r.FindSpoke("node-1").LastHeartbeat = now.Add(-1 * time.Second)
	r.ReconcileLiveness(now, 2*time.Minute)
	if got := r.FindSpoke("node-1").Status; got != StatusOffline {
		t.Fatalf("offline should be sticky, got %q", got)
	}

	// Degraded status is sticky too.
	_ = r.SetStatus("node-1", StatusDegraded)
	r.ReconcileLiveness(now, 2*time.Minute)
	if got := r.FindSpoke("node-1").Status; got != StatusDegraded {
		t.Fatalf("degraded should be sticky, got %q", got)
	}

	// SetStatus rejects unknown values.
	if err := r.SetStatus("node-1", SpokeStatus("bogus")); err == nil {
		t.Fatalf("expected error for invalid status")
	}
	// SetStatus reports unknown node.
	if err := r.SetStatus("nope", StatusActive); err == nil {
		t.Fatalf("expected error for unknown node")
	}
}

func TestUpsertAndRemove(t *testing.T) {
	r := NewRegistry()
	if err := r.UpsertSpoke(SpokeRecord{NodeID: "", Name: "x"}); err == nil {
		t.Fatalf("expected error for empty node_id")
	}
	if err := r.UpsertSpoke(SpokeRecord{NodeID: "a", Status: SpokeStatus("???")}); err == nil {
		t.Fatalf("expected error for bad status on upsert")
	}

	// Default status when omitted on upsert.
	if err := r.UpsertSpoke(SpokeRecord{NodeID: "a", Name: "a"}); err != nil {
		t.Fatalf("upsert: %v", err)
	}
	if got := r.FindSpoke("a").Status; got != StatusRegistered {
		t.Fatalf("default status: got %q", got)
	}

	// Replace by node_id.
	_ = r.UpsertSpoke(SpokeRecord{NodeID: "a", Name: "a2", Status: StatusActive})
	if r.FindSpoke("a").Name != "a2" {
		t.Fatalf("upsert replace failed")
	}
	if len(r.Spokes) != 1 {
		t.Fatalf("upsert duplicated row")
	}

	if !r.RemoveSpoke("a") {
		t.Fatalf("remove existing returned false")
	}
	if r.RemoveSpoke("a") {
		t.Fatalf("remove missing returned true")
	}
}

func TestConcurrentWriteSafety(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "federation-state.json")

	const n = 16
	var wg sync.WaitGroup
	wg.Add(n)
	for i := 0; i < n; i++ {
		i := i
		go func() {
			defer wg.Done()
			r := NewRegistry()
			_ = r.UpsertSpoke(SpokeRecord{
				NodeID:       "node-" + string(rune('a'+i)),
				Name:         "n",
				URL:          "https://x",
				Status:       StatusActive,
				LastHeartbeat: time.Now().UTC(),
			})
			if err := SaveStateTo(path, r); err != nil {
				t.Errorf("concurrent save: %v", err)
			}
		}()
	}
	wg.Wait()

	// File must be parseable after the storm — atomic rename guarantees this.
	got, err := LoadStateFrom(path)
	if err != nil {
		t.Fatalf("load after concurrent writes: %v", err)
	}
	if got.SchemaVersion != CurrentSchemaVersion {
		t.Fatalf("schema_version corrupted under concurrency: %q", got.SchemaVersion)
	}
	// No leftover tmpfiles.
	entries, _ := os.ReadDir(dir)
	for _, e := range entries {
		if strings.HasSuffix(e.Name(), ".tmp") {
			t.Fatalf("leftover tmpfile after concurrent saves: %s", e.Name())
		}
	}
}

func TestSchemaMigrationStub(t *testing.T) {
	// Files written without schema_version (pre-versioned) load as
	// CurrentSchemaVersion. This is the migration stub: the read path is
	// where future version dispatch will hook in.
	dir := t.TempDir()
	path := filepath.Join(dir, "federation-state.json")
	legacy := []byte(`{"spokes":[{"node_id":"n1","name":"old","url":"https://o","status":"active","registered_at":"2026-05-02T19:58:33Z","last_heartbeat":"2026-05-02T20:00:00Z"}]}`)
	if err := os.WriteFile(path, legacy, 0o600); err != nil {
		t.Fatalf("write legacy: %v", err)
	}
	r, err := LoadStateFrom(path)
	if err != nil {
		t.Fatalf("load legacy: %v", err)
	}
	if r.SchemaVersion != CurrentSchemaVersion {
		t.Fatalf("legacy file should default to current schema_version, got %q", r.SchemaVersion)
	}
	if len(r.Spokes) != 1 || r.Spokes[0].NodeID != "n1" {
		t.Fatalf("legacy spokes not preserved: %+v", r.Spokes)
	}
}

func TestDefaultStatePathHonorsXDG(t *testing.T) {
	t.Setenv("XDG_DATA_HOME", "/tmp/xdg-fake")
	p, err := DefaultStatePath()
	if err != nil {
		t.Fatalf("path: %v", err)
	}
	want := filepath.Join("/tmp/xdg-fake", "ddx", "federation-state.json")
	if p != want {
		t.Fatalf("path: got %q want %q", p, want)
	}

	t.Setenv("XDG_DATA_HOME", "")
	p, err = DefaultStatePath()
	if err != nil {
		t.Fatalf("path: %v", err)
	}
	if !strings.HasSuffix(p, filepath.Join(".local", "share", "ddx", "federation-state.json")) {
		t.Fatalf("default path missing ~/.local/share/ddx suffix: %q", p)
	}
}
